import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    shortest_distance = np.inf
    next_node = None

    for node in unvisited_nodes:
        dist_from_current = distance_matrix[current_node][node]
        dist_to_depot = distance_matrix[node][depot_node]
        truck_dist = 0

        if node in truck_nodes:
            truck_dist = distance_matrix[current_node][node]

        total_distance = dist_from_current + dist_to_depot + truck_dist

        if total_distance < shortest_distance:
            shortest_distance = total_distance
            next_node = node
        elif total_distance == shortest_distance:
            if np.random.randint(2) == 0:
                next_node = node

    return next_node
